  1	import React, { FC, useEffect, useMemo, useState } from 'react';
  2	
  3	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import usePagination from '@kubevirt-utils/hooks/usePagination/usePagination';
  6	import { paginationDefaultValues } from '@kubevirt-utils/hooks/usePagination/utils/constants';
  7	import { columnSorting } from '@kubevirt-utils/utils/utils';
  8	import { ListPageBody } from '@openshift-console/dynamic-plugin-sdk';
  9	import { Flex, FlexItem, Pagination, Title } from '@patternfly/react-core';
 10	import { Table, Th, Thead, Tr } from '@patternfly/react-table';
 11	
 12	import useDiagnosticDataVolumeStatusTableColumns from '../hooks/useDiagnosticDataVolumeStatusTableColumns';
 13	import { VirtualizationDataVolumeStatus } from '../utils/types';
 14	import VirtualMachineDiagnosticTabRow from '../VirtualMachineDiagnosticTabRow';
 15	
 16	type VirtualMachineDiagnosticTabDataVolumeStatusProps = {
 17	  dataVolumesStatuses: VirtualizationDataVolumeStatus[];
 18	};
 19	
 20	const VirtualMachineDiagnosticTabDataVolumeStatus: FC<
 21	  VirtualMachineDiagnosticTabDataVolumeStatusProps
 22	> = ({ dataVolumesStatuses }) => {
 23	  const { t } = useKubevirtTranslation();
 24	  const [expend, setExpend] = useState<{ [key: string]: Set<string> }>({
 25	    expended: new Set(),
 26	    ids: new Set(),
 27	  });
 28	
 29	  const { columns, sorting } = useDiagnosticDataVolumeStatusTableColumns();
 30	  const { onPaginationChange, pagination } = usePagination();
 31	  const sortedData = useMemo(
 32	    () => columnSorting(dataVolumesStatuses, sorting?.direction, pagination, sorting?.column),
 33	    [dataVolumesStatuses, sorting, pagination],
 34	  );
 35	
 36	  useEffect(
 37	    () =>
 38	      dataVolumesStatuses.forEach(({ id }) => {
 39	        setExpend((expendObj) => {
 40	          return { expended: new Set(), ids: new Set(expendObj?.ids).add(id) };
 41	        });
 42	      }),
 43	    [dataVolumesStatuses],
 44	  );
 45	
 46	  return (
 47	    <>
 48	      <ListPageBody>
 49	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
 50	          <FlexItem>
 51	            <Title className="VirtualMachineDiagnosticTab--header" headingLevel="h2">
 52	              {t('DataVolume status')}{' '}
 53	              <HelpTextIcon
 54	                bodyContent={t(
 55	                  'DataVolume Status is a mechanism for reporting if a volume succeed.',
 56	                )}
 57	                helpIconClassName="VirtualMachineDiagnosticTab--HelpTextIcon"
 58	              />
 59	            </Title>
 60	          </FlexItem>
 61	          <FlexItem>
 62	            <Pagination
 63	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
 64	                onPaginationChange({ endIndex, page, perPage, startIndex })
 65	              }
 66	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
 67	                onPaginationChange({ endIndex, page, perPage, startIndex })
 68	              }
 69	              isLastFullPageShown
 70	              itemCount={sortedData?.length}
 71	              page={pagination?.page}
 72	              perPage={pagination?.perPage}
 73	              perPageOptions={paginationDefaultValues}
 74	            />
 75	          </FlexItem>
 76	        </Flex>
 77	      </ListPageBody>
 78	
 79	      <Table isExpandable>
 80	        <Thead>
 81	          <Tr>
 82	            <Th
 83	              expand={{
 84	                areAllExpanded: expend.expended.size !== expend.ids.size,
 85	                collapseAllAriaLabel: '',
 86	                onToggle: (_, __, isOpen) => {
 87	                  setExpend((expendObj) => ({
 88	                    expended: new Set(!isOpen ? [] : expendObj.ids),
 89	                    ids: new Set(expendObj?.ids),
 90	                  }));
 91	                },
 92	              }}
 93	            />
 94	            {columns?.map(({ cell: { sort }, title }, index) => {
 95	              return (
 96	                <Th key={title} sort={sort(index)}>
 97	                  {title}
 98	                </Th>
 99	              );
100	            })}
101	          </Tr>
102	        </Thead>
103	        {sortedData.map((row, index) => (
104	          <VirtualMachineDiagnosticTabRow
105	            activeColumns={columns}
106	            dataVolumeResourceLink
107	            expend={expend}
108	            index={index}
109	            key={row?.name}
110	            obj={row}
111	            setExpend={setExpend}
112	          />
113	        ))}
114	      </Table>
115	    </>
116	  );
117	};
118	
119	export default VirtualMachineDiagnosticTabDataVolumeStatus;

